import{_ as e,o as s,c as i,a2 as l}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Sentinel, Cluster y escalado","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/redis/13-sentinel-cluster-y-escalado.md","filePath":"bases-de-datos/redis/13-sentinel-cluster-y-escalado.md","lastUpdated":1782521464000}'),t={name:"bases-de-datos/redis/13-sentinel-cluster-y-escalado.md"};function n(o,a,r,p,c,d){return s(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="sentinel-cluster-y-escalado" tabindex="-1">Sentinel, Cluster y escalado <a class="header-anchor" href="#sentinel-cluster-y-escalado" aria-label="Permalink to &quot;Sentinel, Cluster y escalado&quot;">​</a></h1><p>Redis puede crecer en disponibilidad y capacidad, pero cada opcion resuelve un problema distinto. Replica, Sentinel y Cluster no son sinonimos.</p><h2 id="replicacion-simple" tabindex="-1">Replicacion simple <a class="header-anchor" href="#replicacion-simple" aria-label="Permalink to &quot;Replicacion simple&quot;">​</a></h2><p>Un primario replica datos a una o varias replicas.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P[&quot;Primary&quot;] --&gt; R1[&quot;Replica 1&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P --&gt; R2[&quot;Replica 2&quot;]</span></span></code></pre></div><p>Sirve para:</p><ul><li>Tener copia caliente.</li><li>Descargar algunas lecturas.</li><li>Preparar failover manual.</li></ul><p>No resuelve automaticamente la promocion si cae el primario.</p><h2 id="sentinel" tabindex="-1">Sentinel <a class="header-anchor" href="#sentinel" aria-label="Permalink to &quot;Sentinel&quot;">​</a></h2><p>Redis Sentinel monitoriza instancias y puede promover una replica si el primario falla.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TB</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  S1[&quot;Sentinel 1&quot;] --&gt; P[&quot;Primary&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  S2[&quot;Sentinel 2&quot;] --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  S3[&quot;Sentinel 3&quot;] --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P --&gt; R1[&quot;Replica&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P --&gt; R2[&quot;Replica&quot;]</span></span></code></pre></div><p>Funciones:</p><ul><li>Monitorizacion.</li><li>Deteccion de fallo.</li><li>Eleccion de nuevo primario.</li><li>Notificacion a clientes.</li></ul><h2 id="quorum" tabindex="-1">Quorum <a class="header-anchor" href="#quorum" aria-label="Permalink to &quot;Quorum&quot;">​</a></h2><p>Sentinel necesita acuerdo para declarar caido un primario. Por eso se usan varias instancias Sentinel.</p><p>Configuracion conceptual:</p><div class="language-conf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sentinel monitor mymaster 10.0.0.10 6379 2</span></span></code></pre></div><p>El <code>2</code> indica cuantos Sentinel deben estar de acuerdo.</p><h2 id="redis-cluster" tabindex="-1">Redis Cluster <a class="header-anchor" href="#redis-cluster" aria-label="Permalink to &quot;Redis Cluster&quot;">​</a></h2><p>Redis Cluster distribuye claves entre nodos mediante hash slots.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C[&quot;Cliente&quot;] --&gt; N1[&quot;Nodo A\\nslots 0-5460&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C --&gt; N2[&quot;Nodo B\\nslots 5461-10922&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C --&gt; N3[&quot;Nodo C\\nslots 10923-16383&quot;]</span></span></code></pre></div><p>Sirve para:</p><ul><li>Escalar memoria horizontalmente.</li><li>Repartir escrituras.</li><li>Mantener alta disponibilidad con replicas por master.</li></ul><h2 id="hash-slots" tabindex="-1">Hash slots <a class="header-anchor" href="#hash-slots" aria-label="Permalink to &quot;Hash slots&quot;">​</a></h2><p>Redis Cluster tiene 16384 slots. Cada clave pertenece a un slot.</p><p>Claves con hash tag:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pedido:{10}:datos</span></span>
<span class="line"><span>pedido:{10}:lineas</span></span></code></pre></div><p>Ambas usan el mismo hash tag <code>{10}</code> y caen en el mismo slot. Es importante para operaciones multi-key.</p><h2 id="limitaciones-multi-key" tabindex="-1">Limitaciones multi-key <a class="header-anchor" href="#limitaciones-multi-key" aria-label="Permalink to &quot;Limitaciones multi-key&quot;">​</a></h2><p>En Cluster, operaciones con varias claves pueden fallar si las claves estan en slots distintos.</p><p>Ejemplo problematico:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">MGET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user:1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> order:9</span></span></code></pre></div><p>Si necesitas multi-key, disena claves con hash tags.</p><h2 id="escalado-vertical-vs-horizontal" tabindex="-1">Escalado vertical vs horizontal <a class="header-anchor" href="#escalado-vertical-vs-horizontal" aria-label="Permalink to &quot;Escalado vertical vs horizontal&quot;">​</a></h2><p>Antes de usar Cluster, pregunta:</p><ul><li>El problema es memoria?</li><li>El problema es CPU?</li><li>El problema es red?</li><li>El problema son comandos lentos?</li><li>El modelo de claves soporta particionado?</li></ul><p>Cluster anade complejidad. No lo uses solo porque suena mas avanzado.</p><h2 id="backups-y-replicas" tabindex="-1">Backups y replicas <a class="header-anchor" href="#backups-y-replicas" aria-label="Permalink to &quot;Backups y replicas&quot;">​</a></h2><p>Replica no es backup. Si borras datos en el primario, el borrado se replica.</p><p>Necesitas:</p><ul><li>Snapshots.</li><li>AOF si aplica.</li><li>Copias externas.</li><li>Pruebas de restore.</li></ul><h2 id="clientes" tabindex="-1">Clientes <a class="header-anchor" href="#clientes" aria-label="Permalink to &quot;Clientes&quot;">​</a></h2><p>Las aplicaciones deben usar clientes compatibles con Sentinel o Cluster si esa es la arquitectura.</p><p>Revisa:</p><ul><li>Descubrimiento de primario.</li><li>Reconexiones.</li><li>Timeouts.</li><li>Retry policy.</li><li>Soporte de TLS y auth.</li></ul><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Usa Sentinel para alta disponibilidad de una instancia primaria.</li><li>Usa Cluster cuando necesitas repartir datos y escrituras.</li><li>No confundas replicas con backups.</li><li>Prueba failover antes de produccion.</li><li>Disena claves pensando en slots si usas Cluster.</li></ul>`,47)])])}const m=e(t,[["render",n]]);export{h as __pageData,m as default};
